RooDalitzAmplitude::RooDalitzAmplitude( TList *resList,
	TList *cpList,
	TList *effList,
	double ML,
	double MR,
	double FFR,
	double FFB) : 
   _resList(resList), _cpList(cpList), _effList(effList),
   np_dlzx(50), np_dlzy(500), dlz_hx(1), dlz_lx(-1),
   _ML(ML), _MR(MR),
   _iflat(1),_FFR(FFR),_FFB(FFB),_myKm()
{ 
   //m_bs = 5.36688;
   m_bs = 5.27965;
   m_pi = 0.13957061;
   m_jpsi = 3.096900;
   //m_pi = 0.493677;
   m2_bs = m_bs*m_bs;
   m2_pi = m_pi*m_pi;
   m2_jpsi = m_jpsi*m_jpsi;

   dlz_ly = 2*m_pi;
   dlz_hy = m_bs-m_jpsi;

   int nres = _resList->GetSize();
   std::cout << " Number of Resonances : " << nres << std::endl;
   //each set to 3 parms.
   int ncached = 3*nres;
   _resParCache = new Double_t[ncached];
   for (int i=0; i<ncached; i++) _resParCache[i]=0; 
   _resSpnCache = new Double_t[3*NSP];
   for (int i=0; i<3*NSP; i++) _resSpnCache[i]=0;    

   assert(nres<=MYRN); 

   for(int i=0; i<nres; ++i) {
	for(int ih=0; ih<3; ++ih) {
	   HHR[i][ih] = TComplex(0.0,0.0);
	   HHRbar[i][ih] = TComplex(0.0,0.0);
	}
   }
   pdlz = std::make_shared<std::vector<Jpsihh_dlz*>>();

   double hx = (dlz_hx-dlz_lx)/2./(np_dlzx);
   double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);
   //  int sum = 0;
   for(int i=0; i<2*np_dlzx; ++i) {  
	for(int j=0; j<2*(np_dlzy); ++j) {
	   Jpsihh_dlz *p = new Jpsihh_dlz();
	   p->cospp = dlz_lx+i*hx+0.5*hx;
	   // cout << p.cospp << endl;
	   p->mpp = dlz_ly+j*hy+0.5*hy;
	   if(kine_limits(p->mpp)) {
		for(int ir=0; ir<nres; ++ir) {
		   for(int ih=0; ih<3; ++ih) {
			p->dre[ir][ih] = 0.0;
			p->dim[ir][ih] = 0.0;
		   }
		}
		p->Inte[0]=0.0; p->Inte[1]=0.0; p->Inte[2]=0.0;
		double pB = getpB(p->mpp);
		double pR = getpR(p->mpp);
		double xeff = 1.0;
		double effphsp = pR*pB*xeff;        
		p->phsp =effphsp;
		if(p->mpp>=ML&&p->mpp<MR)  pdlz->push_back(p);
		//	sum++;
	   }
	}
   }
   //reset FFR and FFB to PDG value
   //  _FFR = 3.0;
   //  _FFB = 3.0;
   _isPHSPGen = false;
   _myKm.SetValues();
   std::cout << " Integration grids " << pdlz->size()  <<std::endl;     
   //  std::cout << "eff. para. " << ((RooAbsReal&)peff_[0]).getVal() << endl;
}


