Bool_t RooDalitzAmplitude::kine_limits(double mpp) const
{
   if(mpp<2*m_pi) return false;
   if(mpp>m_bs-m_jpsi) return false;
   return true;
}

Bool_t RooDalitzAmplitude::kine_limits(double m2kp, double m2pp) const
{
   //   Return 1 if masses are in allowed kinematic region for Dalitz plot
   double m2km;
   double mkp,mpp,mkm;
   double p2m, p2p, p2k;
   double ep_star, em_star;
   double pp_star, pm_star, e_sum2;
   double m2pp_min, m2pp_max;

   //  m2kp = (double) m_12;
   //  m2pp = (double) m_13;
   //  m2km = (double) m_13;

   m2km = m2_bs - m2kp - m2pp + 2*m2_pi + m2_jpsi;

   if(m2pp<0) return false;
   mkp = sqrt(m2kp);
   mkm = sqrt(m2km);
   mpp = sqrt(m2pp);

   p2m = 1./4./m2_bs*(m2_bs-pow(mkp+m_pi,2))*(m2_bs-pow(mkp-m_pi,2));
   p2p = 1./4./m2_bs*(m2_bs-pow(mkm+m_pi,2))*(m2_bs-pow(mkm-m_pi,2));
   p2k = 1./4./m2_bs*(m2_bs-pow(mpp+m_jpsi,2))*(m2_bs-pow(mpp-m_jpsi,2));

   ep_star=(m2kp-m2_jpsi+m2_pi)/2./mkp;
   em_star=(m2_bs-m2kp-m2_pi)/2./mkp;
   if(ep_star<m_pi || em_star< m_pi) return false;

   pp_star= sqrt(pow(ep_star,2)-m2_pi);
   pm_star= sqrt(pow(em_star,2)-m2_pi);
   e_sum2 = pow(ep_star+em_star,2);
   m2pp_max = e_sum2-pow(pp_star-pm_star,2);
   m2pp_min = e_sum2-pow(pp_star+pm_star,2);

   if (m2pp<m2pp_min || m2pp>m2pp_max) return false;
   if (p2m>0&&p2p>0&&p2k>0) return true;
   return false;
}

//convert coshh to m(Jpsih+)
Double_t RooDalitzAmplitude::getM2Jpsih(double mpp, double cospp) const 
{
   double SDP  = m2_bs + 2*m2_pi + m2_jpsi;
   double m2pp = mpp*mpp;
   double pB = getpB(mpp);
   double pR = getpR(mpp);
   return 0.5*(SDP-m2pp)+2.0*pR*pB*m_bs*cospp/mpp;
} 

