   if(i==5) return (63.*pow(x,5)-70.*x*x*x+15*x)/8.;
   if(i==6) return (231.*pow(x,6)-315.*pow(x,4)+105*x*x-5)/16.;
   if(i==7) return (429.*pow(x,7)-693.*pow(x,5)+315.*pow(x,3)-35*x)/16.;
