//convert to Real using cos(phi), x 2 for complex ones
Double_t RooDalitzAmplitude::YM(double cosx, double phi, int l, int m) const
{
   double x = cosx;
   double pi = TMath::Pi();
   if(l==0&&m==0) return 0.5/sqrt(pi);
   if(l==1&&m==0) return 0.5*sqrt(3./pi)*x;
   if(l==1&&m==1) return -sqrt(1.5/pi)*sqrt(1-x*x)*cos(phi);
   if(l==2&&m==0) return 0.25*sqrt(5./pi)*(3*x*x-1);
   if(l==2&&m==1) return -sqrt(15./2./pi)*sqrt(1-x*x)*x*cos(phi);
   if(l==2&&m==2) return 0.5*sqrt(15./2./pi)*(1-x*x)*cos(2.*phi);
   if(l==3&&m==1) return -1./4.*sqrt(21./pi)*sqrt(1-x*x)*(5.*x*x-1.)*cos(phi);    
   if(l==4&&m==0) return 3./16./sqrt(pi)*(35.*pow(x,4)-30.*x*x+3.);
   if(l==4&&m==2) return 3./4.*sqrt(2.5/pi)*(1-x*x)*(7.*x*x-1.)*cos(2.*phi); 
   if(l==5&&m==1) return -1./8.*sqrt(165./2./pi)*(1-14*x*x+21*pow(x,4))*sqrt(1-x*x)*cos(phi);
   if(l==6&&m==0) return 1./32.*sqrt(13./pi)*(-5.+105.*x*x-315*pow(x,4)+231*pow(x,6));
   if(l==6&&m==2) return 1./32.*sqrt(1365./pi)*(1-18*x*x+33*pow(x,4))*(1-x*x)*cos(2.*phi);
   if(l==8&&m==0) return 1./256.*sqrt(17./pi)*(35-1260*x*x+6930*pow(x,4)-12012*pow(x,6)+6435*pow(x,8));
   if(l==8&&m==2) return 3./64.*sqrt(595./pi)*(-1+33*x*x-143*pow(x,4)+143*pow(x,6))*(1-x*x)*cos(2.*phi);  

   return 0;
}

Double_t RooDalitzAmplitude::Seff(double xmhh, double xcoshh, double xcosH, double xphi,
	int a, int b, int c, int d, double ra) const
{
   double mmin = 2*m_pi;
   double mmax = m_bs-m_jpsi;

   double norm_m = 2.*(xmhh-mmin)/(mmax-mmin)-1;
   return YM(xcosH,xphi,b,c)*LegPol(xcoshh,a)*LegPol(norm_m,d)*ra;
}

