Double_t RooDalitzAmplitude::efficiency(double mpp, double cospp, double cosh, double xchi, bool isphi) const
{
   //if(fabs(mpp-0.489)<0.02) return 0.0;
   //cout<<_mKs_l<<" "<<_mKs_h<<endl;
   if( _exlKsRange == 1 ){
	if( mpp>_mKs_l &&mpp< _mKs_h ){
	   return 0.0;
	}
   }

   if(!kine_limits(mpp)) return 0;
   double sum(0);
   double Norm(1.);
   TList *EffList = _effList;
   TIterator* Iter= EffList->MakeIterator();
   while(RooArgList* Ieff = (RooArgList*)Iter->Next()) {
	RooArgList ieff = (*Ieff);
	int a = (int)((RooAbsReal&)ieff[0]).getVal();
	int b = (int)((RooAbsReal&)ieff[1]).getVal();
	int c = (int)((RooAbsReal&)ieff[2]).getVal();
	int d = (int)((RooAbsReal&)ieff[3]).getVal();
	double coef = ((RooAbsReal&)ieff[4]).getVal();
	//    std::cout << a << " " << b << " " << c << " " << d << " " << coef << std::endl;
	sum += Seff(mpp, cospp, cosh, xchi, a,b,c,d,coef);
   }
   delete Iter;
   sum = sum*Norm;
   if(sum<0) {
	//	std::cout << " efficiency check " << mpp << " "  << cospp << " " << sum << std::endl;
	sum=0;
   }
   return sum;
}


Double_t RooDalitzAmplitude::YMIntegral(int index, int l, int m) const
/*
//considering symmetric acceptance i.e. l+m = 2n, only need to do three integration:
index=1 for sin^2, index=2 for (1+cos^2)/2., index=3 sin^2*cos(2chi)
*/
{
   double pi = TMath::Pi();
   if(l==0&&m==0) {
	if(index==1||index==2) return 4.*sqrt(pi)/3.;
	return 0;
   }
   if(l==2&&m==0) {
	if(index==1) return -4./3.*sqrt(pi/5.);
	if(index==2) return 2./3.*sqrt(pi/5.);
	return 0;
   }
   if(l==2&&m==2) {
	if(index==3) return 4.*sqrt(2.*pi/15.);
	return 0;
   }
   return 0;
}

Double_t RooDalitzAmplitude::effcosHchiIntegral(int index, double xmhh, double xcoshh) const
{

   double mmin= 2*m_pi;
   double mmax = m_bs-m_jpsi;
   double norm_m = 2.*(xmhh-mmin)/(mmax-mmin)-1;
   if(!(index>=1&&index<=3)) {std::cout << "index wrong " << std::endl; return 0;}
   double sum(0);
   TList *EffList = _effList;
   double Norm(1.0);
   TIterator* Iter=EffList->MakeIterator();

   while(RooArgList* Ieff = (RooArgList*)Iter->Next()) {
	RooArgList ieff = (*Ieff);
	int a = (int)((RooAbsReal&)ieff[0]).getVal();
	int b = (int)((RooAbsReal&)ieff[1]).getVal();
	int c = (int)((RooAbsReal&)ieff[2]).getVal();
	int d = (int)((RooAbsReal&)ieff[3]).getVal();
	double coef = ((RooAbsReal&)ieff[4]).getVal();
	sum += coef*YMIntegral(index,b,c)*LegPol(xcoshh,a)*LegPol(norm_m,d);
   }

   delete Iter;
   sum = sum * Norm;
   if(sum<0) {
	//cout << "eff check " << mpp << " " << sum << endl;
	sum=0;
   }
   //  cout << "efficiency " << sum << endl;
   return sum;  
}

void RooDalitzAmplitude::filldlz(Jpsihh_dlz &dlz, Double_t xmhh, Double_t xcoshh) const
{
   dlz.cospp = xcoshh;
   dlz.mpp = xmhh;
   int nres = _resList->GetSize();

   for(int ir=0; ir<nres; ++ir) {
	for(int ih=0; ih<3; ++ih) {
	   dlz.dre[ir][ih] = 0.0;
	   dlz.dim[ir][ih] = 0.0;
	}
   }
} 

bool RooDalitzAmplitude::checkchange() const
{

   int ir(0);

   TIterator* coefIter=_resList->MakeIterator();
   while(RooArgList* Ires = (RooArgList*)coefIter->Next()) {
	RooArgList ires = (*Ires);
	int type = (int)((RooAbsReal&)ires[ires.getSize()-1]).getVal();

	//if (type!=1&&type!=2&&type!=3&&type!=4) continue;
	double m0 = 0;
	double g0 = 0;
	double rg = 0;

	if(type==1) { //breit wigner
	   m0 = ((RooAbsReal&)ires[ires.getSize()-4]).getVal();
	   g0 = ((RooAbsReal&)ires[ires.getSize()-3]).getVal();
	} 
	else if(type==2) { //f0 flatte
	   m0 = ((RooAbsReal&)ires[2]).getVal();
	   g0 = ((RooAbsReal&)ires[3]).getVal();
	   rg = ((RooAbsReal&)ires[4]).getVal();
	} else if(type==10) {
	   for(int it3=0; it3<ires.getSize(); ++it3) {
		if(fabs(_resSpnCache[it3]-((RooAbsReal&)ires[it3]).getVal())>1e-20) {
		   delete coefIter;
		   return true;
		}
	   }
	}
	if( 
		//check if need to update cached amplitude if mass or widht changes
		(fabs(_resParCache[3*ir+0]-m0)>1e-20)
		|| (fabs(_resParCache[3*ir+1]-g0)>1e-20)
		|| (fabs(_resParCache[3*ir+2]-rg)>1e-20) ) {
	   delete coefIter;
	   return true;
	}
	ir++;
   }
   delete coefIter;
   return false;
}

