//////////////////////////////////////////////////
//        flatte resonance Amplitude
//////////////////////////////////////////////////
void RooDalitzAmplitude::f0_ampl(double m, double gpi, double rgk, double mpp, double &r_ampl, double &i_ampl) const
{
   double mpip = 0.13957061;
   double mpi0 = 0.1349770;
   double mkp = 0.493677;
   double mk0 = 0.497611;

   double mpip2 = mpip*mpip;
   double mpi02 = mpi0*mpi0;
   double mkp2 = mkp*mkp;
   double mk02 = mk0*mk0;
   double mf0 = m;
   double gk = gpi*rgk;

   double mpipi = mpp*mpp;

   //bugg
   double alpha = 2.0;
   double fkk=1.0;
   if(mpipi/4.0>mkp2) {
	double pk2 = fabs(mpipi/4.0-mkp2);
	fkk = exp(-alpha*pk2);
	gk = gk*fkk*fkk;
   }

   r_ampl = 0;
   i_ampl = 0;
   if(1.-4.*mpip2/mpipi<0) return;
   double rhopi = (2.*sqrt(1.-4.*mpip2/mpipi)+sqrt(1.-4.*mpi02/mpipi))/3*mf0*gpi;
   double re=mf0*mf0-mpipi;

   double im = rhopi;

   double rhok;
   //   double factor = sqrt(mpipi/4.-mpip2);
   if(mpipi<4*mkp2) {
	rhok=(sqrt(4.*mkp2/mpipi-1.)+sqrt(4.*mk02/mpipi-1.))/2.*mf0*gk;
	re = re+rhok;
   } else if(mpipi<4*mk02) {
	rhok = sqrt(4.*mk02/mpipi-1)/2.*mf0*gk;
	re = re+rhok;
	im = im+sqrt(1.-4.*mkp2/mpipi)/2.*mf0*gk;
   }  else {
	rhok = (sqrt(1.-4.*mkp2/mpipi)+sqrt(1-4.*mk02/mpipi))/2.*mf0*gk;
	im = im+rhok;
   }

   double d = (re*re+im*im);

   //double pB=getpB(mpp);//sqrt((m2_bs-(m_jpsi+mpp)*(m_jpsi+mpp))*(m2_bs-(m_jpsi-mpp)*(m_jpsi-mpp)))/2./m_bs;
   //double pB0=getpB(m);//sqrt((m2_bs-(m_jpsi+m)*(m_jpsi+m))*(m2_bs-(m_jpsi-m)*(m_jpsi-m)))/2./m_bs;
   //double FB = F_BW(_FFB,1,pB,pB0);
   double factor =1.;// FB*(pB/m_bs);
   r_ampl = factor*(re/d);
   i_ampl = factor*(im/d);
}

//======================
//hep-ph/0608081 for sigma
//=====================
void RooDalitzAmplitude::sigmanew_ampl( double mpp, double &r_ampl, double &i_ampl) const
{
   double mpipi = mpp*mpp;
   double s = mpipi;
   //  double mpp=sqrt(mpipi);

   double mpip = 0.13957061;
   double mpip2 = mpip*mpip;   
   double mKp = 0.493677;
   double mKp2 = mKp*mKp; 
   double mEt = 0.547853;
   double mEt2 = mEt*mEt;

   r_ampl = 0; 
   i_ampl = 0;
   if(1.-4.*mpip2/mpipi<0) return;
   //parameters 
   double b1(1.302), b2(0.340), A(2.426);  
   double alpha(1.3), g4(0.011);
   double sA = 0.41*mpip2;
   double M = 0.953;
   double M2 = M*M;  

   double rhopi = sqrt(1.-4.*mpip2/s);//(2.*sqrt(1.-4.*mpip2/s)
   //+sqrt(1.-4.*mpi02/s))/3.0;
   double rhopi0 = sqrt(1.-4.*mpip2/M2);//(2.*sqrt(1.-4.*mpip2/m2)
   //		   +sqrt(1.-4.*mpi02/m2))/3.0;
   double im(0),re(0);
   double j1 = 2.0+rhopi*log((1-rhopi)/(1+rhopi));
   double j10 = 2.0+rhopi0*log((1-rhopi0)/(1+rhopi0));
   double z = (j1-j10)/TMath::Pi();

   //MGamma_pipi
   double fs = b1+b2*s;
   double g12 = M*fs*exp(-1.0*(s-M2)/A);
   double Albet = g12*(s-sA)/(M2-sA);
   double MG1 = Albet*rhopi;
   im = MG1;
   re = M2-s-Albet*z;

   //MGamma_KK;
   double rhoK = sqrt(fabs(1.-4*mKp2/s));    
   double MG2 = 0.6*g12*(s/M2)*exp(-alpha*fabs(s-4*mKp2))*rhoK;  
   if(1.-4*mKp2/s>0) {
	im += MG2;
   } else {
	re += MG2;
   }
   //MGamma_etaeta
   double rhoE = sqrt(fabs(1.-4*mEt2/s));
   double MG3 = 0.2*g12*(s/M2)*exp(-alpha*fabs(s-4*mEt2))*rhoE;  
   if(1.-4*mEt2/s>0) {
	im += MG3;
   } else {
	re += MG3;
   }
   if(s>16*mpip2) {
	double rho4pi = 1.0/(1+exp(7.082-2.845*s));
	double rho4pi0 = 1.0/(1+exp(7.082-2.845*M2));
	double MG4 = M*g4*rho4pi/rho4pi0;
	im = im+MG4;
   }

   double d = (re*re+im*im);

   //  double pB=getpB(mpp);
   //  double pB0=sqrt((m2_bs-(m_jpsi+m)*(m_jpsi+m))*(m2_bs-(m_jpsi-m)*(m_jpsi-m)))/2./m_bs;
   //  double FB = F_BW(5.0,1,pB,pB0);
   double factor = 1;//(pB/m_bs);
   r_ampl = factor*(re/d);
   i_ampl = factor*(im/d);
} 

